import React, { useEffect, useState } from 'react';
import { useHistory, useLocation } from 'react-router-dom';
// import '../styles/AuthForm.css';

const ResetPassword = () => {
    const location = useLocation();
    const navigate = useHistory();
    const [data, setData] = useState({
        email: "",
        newPassword: "",
        confirmPassword: ""
    });
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');

    const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
    const validValue = data.newPassword && data.confirmPassword && data.newPassword === data.confirmPassword;

    useEffect(() => {
        if (!(location?.state?.data?.success)) {
            navigate.push("/");
        }

        if (location?.state?.email) {
            setData((prev) => ({
                ...prev,
                email: location?.state?.email
            }));
        }
    }, []);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setData((prev) => ({
            ...prev,
            [name]: value
        }));
        
        // Clear error when user starts typing
        if (error) setError('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setMessage('');

        // Validation
        if (data.newPassword !== data.confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        if (data.newPassword.length < 6) {
            setError('Password must be at least 6 characters long');
            return;
        }

        setIsLoading(true);

        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/reset-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    email: data.email,
                    newPassword: data.newPassword,
                    token: location?.state?.data?.resetToken
                })
            });

            const result = await response.json();

            if (!response.ok) {
                throw new Error(result.message || 'Failed to reset password');
            }

            setMessage('Password reset successfully! Redirecting to login...');
            setTimeout(() => {
                navigate.push("/");
            }, 2000);

        } catch (error) {
            console.error('Reset password error:', error);
            setError(error.message || 'Failed to reset password. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-form-wrapper">
                <div className="auth-header">
                    <div className="login-logo">
                        <div className="ring-container">
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="ring"></div>
                            <div className="logo-text">FORUM ACADEMY</div>
                        </div>
                    </div>
                    <h2>Reset Password</h2>
                    <p>Create a new password for your account</p>
                </div>

                {error && (
                    <div className="form-error modern">
                        <span className="material-icons">error_outline</span>
                        <span>{error}</span>
                    </div>
                )}

                {message && (
                    <div className="form-success modern">
                        <span className="material-icons">check_circle</span>
                        <span>{message}</span>
                    </div>
                )}

                <form className="auth-form" onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="newPassword">New Password:</label>
                        <div className="input-wrapper">
                            <span className="material-icons input-icon">lock</span>
                            <input
                                type={showPassword ? "text" : "password"}
                                id="newPassword"
                                name="newPassword"
                                value={data.newPassword}
                                onChange={handleChange}
                                placeholder="Enter your new password"
                                required
                                className="form-input modern"
                                autoFocus
                            />
                            <button
                                type="button"
                                className="toggle-password"
                                onClick={() => setShowPassword(!showPassword)}
                                tabIndex="-1"
                            >
                                <span className="material-icons">
                                    {showPassword ? 'visibility_off' : 'visibility'}
                                </span>
                            </button>
                        </div>
                    </div>

                    <div className="form-group">
                        <label htmlFor="confirmPassword">Confirm Password:</label>
                        <div className="input-wrapper">
                            <span className="material-icons input-icon">lock</span>
                            <input
                                type={showConfirmPassword ? "text" : "password"}
                                id="confirmPassword"
                                name="confirmPassword"
                                value={data.confirmPassword}
                                onChange={handleChange}
                                placeholder="Confirm your new password"
                                required
                                className="form-input modern"
                            />
                            <button
                                type="button"
                                className="toggle-password"
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                tabIndex="-1"
                            >
                                <span className="material-icons">
                                    {showConfirmPassword ? 'visibility_off' : 'visibility'}
                                </span>
                            </button>
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={!validValue || isLoading}
                        className={`auth-button ${validValue ? 'enabled' : 'disabled'}`}
                    >
                        {isLoading ? (
                            <>
                                <span className="button-loader"></span>
                                <span>Resetting...</span>
                            </>
                        ) : (
                            <>
                                <span>Reset Password</span>
                                <span className="material-icons button-icon">check</span>
                            </>
                        )}
                    </button>
                </form>

                <div className="auth-footer">
                    <p>
                        Remember your password?{' '}
                        <button
                            type="button"
                            className="link-button"
                            onClick={() => navigate.push("/")}
                        >
                            Back to Login
                        </button>
                    </p>
                </div>
            </div>
        </div>
    );
};

export default ResetPassword;
